"use client";

import React, { useState, useEffect } from "react";

// 1. Task ka structure define kar rahe hain taake TypeScript error na de
interface Task {
id: string;
title: string;
completed: boolean;
}

export default function Dashboard() {
// 2. State ko bataya ke ye Task type ki array hogi
const [tasks, setTasks] = useState<Task[]>([]);
const [input, setInput] = useState("");
const [loading, setLoading] = useState(true);

// 3. Database se tasks mangwane ka function
useEffect(() => {
const fetchTasks = async () => {
try {
const res = await fetch("/api/tasks");
const data = await res.json();
if (Array.isArray(data)) {
setTasks(data as Task[]);
}
} catch (error) {
console.error("Fetch error:", error);
} finally {
setLoading(false);
}
};
fetchTasks();
}, []);

// 4. Naya Task add karne ka function
const addTask = async () => {
if (!input.trim()) return;
try {
const res = await fetch("/api/tasks", {
method: "POST",
headers: { "Content-Type": "application/json" },
body: JSON.stringify({ title: input }),
});

  if (res.ok) {
    const newTask = await res.json();
    // Yahan 'as Task' likhne se prev wala error khatam ho jayega
    setTasks((prev) => [...prev, newTask as Task]);
    setInput("");
  }
} catch (error) {
  console.error("Add error:", error);
}
};

return (
<div style={{ backgroundColor: '#0a0a0a', color: 'white', minHeight: '100vh', padding: '50px', fontFamily: 'sans-serif' }}>
<div style={{ maxWidth: '600px', margin: '0 auto' }}>

    <h1 style={{ fontSize: '32px', fontWeight: 'bold', color: '#60a5fa', marginBottom: '10px' }}>
      Task Orbit
    </h1>
    <p style={{ color: '#666', marginBottom: '30px' }}>Manage your tasks with ease.</p>

    {/* Input Field */}
    <div style={{ display: 'flex', gap: '10px', marginBottom: '30px' }}>
      <input 
        value={input}
        onChange={(e) => setInput(e.target.value)}
        onKeyDown={(e) => e.key === "Enter" && addTask()}
        placeholder="Add a new task..."
        style={{ flex: 1, padding: '12px', borderRadius: '10px', border: '1px solid #333', backgroundColor: '#111', color: 'white', outline: 'none' }}
      />
      <button 
        onClick={addTask}
        style={{ backgroundColor: '#2563eb', color: 'white', border: 'none', padding: '12px 25px', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' }}
      >
        Add
      </button>
    </div>

    {/* Tasks Display */}
    {loading ? (
      <p style={{ color: '#666' }}>Loading your space...</p>
    ) : (
      <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
        {tasks.length === 0 ? (
          <p style={{ color: '#444', textAlign: 'center', marginTop: '20px' }}>Your orbit is empty. Add a task!</p>
        ) : (
          tasks.map((task) => (
            <div 
              key={task.id} 
              style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '15px 20px', background: '#141414', borderRadius: '12px', border: '1px solid #222' }}
            >
              <span style={{ fontSize: '17px', color: '#ddd' }}>{task.title}</span>
              <div style={{ width: '20px', height: '20px', borderRadius: '50%', border: '2px solid #333' }}></div>
            </div>
          ))
        )}
      </div>
    )}

  </div>
</div>
);
}